mapper.select:
SELECT c.id, c.article_id, c.parent_id, c.reply_to_id, c.nickname, c.email, c.content, c.status, c.create_time, a.title AS article_title FROM t_comment c LEFT JOIN t_article a ON c.article_id = a.id WHERE c.deleted = 0
AND c.article_id = #{articleId}
ORDER BY c.create_time DESC LIMIT #{offset}, #{size}
